        var result = QueryCommandRunner.BuildExactZeroHint(
            shouldProbe: true,
            anyRelaxedMatch: () => false,
            relaxedCountQuery: () => throw new InvalidOperationException("count should not run"),
            relaxedSampleQuery: () =>
            {
